$ErrorActionPreference = "Stop"

Write-Host "Criando PWA do app Gestão de Projetos..." -ForegroundColor Cyan

New-Item -ItemType Directory -Force -Path ".\public\icons" | Out-Null
New-Item -ItemType Directory -Force -Path ".\src" | Out-Null

[System.IO.File]::WriteAllBytes(".\\public\\icons\\icon-192.png", [System.Convert]::FromBase64String(""))
[System.IO.File]::WriteAllBytes(".\\public\\icons\\icon-512.png", [System.Convert]::FromBase64String(""))
[System.IO.File]::WriteAllBytes(".\\public\\icons\\maskable-512.png", [System.Convert]::FromBase64String(""))
[System.IO.File]::WriteAllBytes(".\\public\\icons\\apple-touch-icon.png", [System.Convert]::FromBase64String(""))

@'
