'@ | Set-Content -Path ".\public\manifest.webmanifest" -Encoding UTF8

@'
const CACHE_NAME = "gestao-projetos-pwa-v1";
const STATIC_ASSETS = [
  "/",
  "/manifest.webmanifest",
  "/icons/icon-192.png",
  "/icons/icon-512.png",
  "/icons/maskable-512.png",
  "/icons/apple-touch-icon.png"
];

self.addEventListener("install", (event) => {
  self.skipWaiting();

  event.waitUntil(
    caches.open(CACHE_NAME).then((cache) => cache.addAll(STATIC_ASSETS)).catch(() => null)
  );
});

self.addEventListener("activate", (event) => {
  event.waitUntil(
    caches
      .keys()
      .then((keys) =>
        Promise.all(keys.filter((key) => key !== CACHE_NAME).map((key) => caches.delete(key)))
      )
      .then(() => self.clients.claim())
  );
});

self.addEventListener("fetch", (event) => {
  const request = event.request;
  const url = new URL(request.url);

  if (request.method !== "GET") return;
  if (url.origin !== self.location.origin) return;

  if (request.mode === "navigate") {
    event.respondWith(
      fetch(request)
        .then((response) => {
          const copy = response.clone();
          caches.open(CACHE_NAME).then((cache) => cache.put("/", copy));
          return response;
        })
        .catch(() => caches.match("/"))
    );
    return;
  }

  event.respondWith(
    caches.match(request).then((cachedResponse) => {
      if (cachedResponse) return cachedResponse;

      return fetch(request).then((networkResponse) => {
        if (networkResponse && networkResponse.status === 200) {
          const copy = networkResponse.clone();
          caches.open(CACHE_NAME).then((cache) => cache.put(request, copy));
        }

        return networkResponse;
      });
    })
  );
});

'@ | Set-Content -Path ".\public\sw.js" -Encoding UTF8

@'
function registerPWA() {
  if (!("serviceWorker" in navigator)) return;
  if (!import.meta.env.PROD) return;

  window.addEventListener("load", async () => {
    try {
      const registration = await navigator.serviceWorker.register("/sw.js");
      registration.update();
      console.info("PWA registrado:", registration.scope);
    } catch (error) {
      console.warn("Não foi possível registrar o PWA:", error);
    }
  });
}

registerPWA();

'@ | Set-Content -Path ".\src\pwa-register.js" -Encoding UTF8

$indexPath = ".\index.html"

if (!(Test-Path $indexPath)) {
  throw "Não encontrei o arquivo index.html na raiz do projeto."
}

$index = Get-Content -Path $indexPath -Raw

if ($index -notmatch "GESTAO_PROJETOS_PWA_V1") {
  $headBlock = @'
    <!-- GESTAO_PROJETOS_PWA_V1 -->
    <meta name="theme-color" content="#2D1D17" />
    <meta name="mobile-web-app-capable" content="yes" />
    <meta name="apple-mobile-web-app-capable" content="yes" />
    <meta name="apple-mobile-web-app-status-bar-style" content="default" />
    <meta name="apple-mobile-web-app-title" content="AD Projetos" />
    <link rel="manifest" href="/manifest.webmanifest" />
    <link rel="apple-touch-icon" href="/icons/apple-touch-icon.png" />
    <link rel="icon" type="image/png" sizes="192x192" href="/icons/icon-192.png" />
'@

  $index = $index -replace "</head>", "$headBlock`r`n  </head>"
}

if ($index -notmatch "pwa-register.js") {
  $index = $index -replace "</body>", "    <script type=`"module`" src=`"/src/pwa-register.js`"></script>`r`n  </body>"
}

Set-Content -Path $indexPath -Value $index -Encoding UTF8

Write-Host "PWA criado com sucesso." -ForegroundColor Green
Write-Host "Arquivos criados/atualizados:" -ForegroundColor Green
Write-Host " - public/manifest.webmanifest"
Write-Host " - public/sw.js"
Write-Host " - public/icons/icon-192.png"
Write-Host " - public/icons/icon-512.png"
Write-Host " - public/icons/maskable-512.png"
Write-Host " - public/icons/apple-touch-icon.png"
Write-Host " - src/pwa-register.js"
Write-Host " - index.html"
